previewCss:
.darma-loader-darma-custom-552 {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
   width: 60px;
   aspect-ratio: 1;
   padding: 10px;
   box-sizing: border-box;
   display: grid;
}
.darma-loader-darma-custom-552, .darma-loader-darma-custom-552:before, .darma-loader-darma-custom-552:after  {
  --c:no-repeat linear-gradient(var(--loader-color, #f97316) 0 0);
   background: var(--c), var(--c), var(--c), var(--c);
   animation: darma-loader-darma-custom-552-l18-1 1.5s infinite cubic-bezier(0,0,1,1), darma-loader-darma-custom-552-l18-2 1.5s infinite;
}
.darma-loader-darma-custom-552:before, .darma-loader-darma-custom-552:after  {
  content: "";
   grid-area: 1/1;
   animation-timing-function: cubic-bezier(0,0.2,1,1),linear;
}
.darma-loader-darma-custom-552:after  {
  margin: 10px;
   animation-timing-function: cubic-bezier(0,0.4,1,1),linear;
}
@keyframes darma-loader-darma-custom-552-l18-1  {
  0%, 10% {background-size: 0 4px,4px 0 }
40%, 60% {background-size: 100% 4px,4px 100%}
90%, 100% {background-size: 0 4px,4px 0 }
}
@keyframes darma-loader-darma-custom-552-l18-2  {
  0%,49.9%{background-position: 0 0,0 0,100% 100%,100% 100%}
50%,100%{background-position: 100% 0,0 100%,0 100%,100% 0}
}

